/**
 * Shared Authentication Utilities
 * Centralized functions for getting current user info and company context
 * Used by all services to avoid code duplication
 */

export interface CurrentUserInfo {
  uid: string
  role: string
  companyId: string
  displayName?: string
  email?: string
  companyName?: string
}

interface StoredUserSnapshot {
  uid?: string
  role?: string
  companyId?: string
  email?: string
  companyName?: string
  displayName?: string
}

const SETTINGS_STORAGE_PREFIX = 'thisai_crm_settings'
const DEFAULT_COMPANY_NAME = 'Your Company Name'

const getStoredUser = (): StoredUserSnapshot | null => {
  try {
    const userRaw = localStorage.getItem('user')
    if (!userRaw) return null
    return JSON.parse(userRaw) as StoredUserSnapshot
  } catch {
    return null
  }
}

const normalizeCompanyId = (value?: string | null): string | null => {
  const normalized = String(value || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')

  return normalized || null
}

const getCompanyNameFromSettingsStorage = (): string | null => {
  try {
    for (let i = 0; i < localStorage.length; i += 1) {
      const key = localStorage.key(i)
      if (!key || !key.startsWith(SETTINGS_STORAGE_PREFIX)) continue

      const raw = localStorage.getItem(key)
      if (!raw) continue

      const parsed = JSON.parse(raw) as { company?: { companyName?: string } }
      const companyName = String(parsed?.company?.companyName || '').trim()
      if (companyName && companyName !== DEFAULT_COMPANY_NAME) {
        return companyName
      }
    }
  } catch {
    return null
  }

  return null
}

const resolveCompanyIdFromSnapshot = (user: StoredUserSnapshot | null): string | null => {
  if (user?.companyId) {
    return normalizeCompanyId(user.companyId)
  }

  const companyName = String(user?.companyName || '').trim()
  const email = String(user?.email || '').trim().toLowerCase()
  const settingsCompanyName = getCompanyNameFromSettingsStorage()

  return normalizeCompanyId(companyName || settingsCompanyName || email)
}

const persistResolvedCompanyId = (user: StoredUserSnapshot | null, companyId: string | null): void => {
  if (!user || !companyId || user.companyId === companyId) return

  try {
    localStorage.setItem('user', JSON.stringify({
      ...user,
      companyId
    }))
  } catch {
    // Ignore localStorage write failures; caller can still use the resolved value.
  }
}

/**
 * Get current company ID from stored user data
 * Used for multi-tenant data isolation
 */
export const getCurrentCompanyId = (): string | null => {
  const user = getStoredUser()
  const companyId = resolveCompanyIdFromSnapshot(user)
  persistResolvedCompanyId(user, companyId)
  return companyId
}

/**
 * Get current user ID from stored user data
 */
export const getCurrentUserId = (): string | null => {
  const user = getStoredUser()
  return user?.uid || null
}

/**
 * Get a scoped localStorage key for the current user/company
 * - scope='company' uses companyId
 * - scope='user' uses uid
 * - scope='auto' prefers companyId, falls back to uid
 */
export const getScopedStorageKey = (
  baseKey: string,
  scope: 'company' | 'user' | 'auto' = 'auto'
): string => {
  const user = getStoredUser()
  const companyId = getCurrentCompanyId()
  const scopeId = scope === 'company'
    ? companyId
    : scope === 'user'
      ? user?.uid
      : (companyId || user?.uid)

  return scopeId ? `${baseKey}_${scopeId}` : `${baseKey}_anonymous`
}

/**
 * Get current user info including uid, role, and companyId
 * Used for role-based access control
 */
export const getCurrentUserInfo = (): CurrentUserInfo | null => {
  const user = getStoredUser()
  if (!user) return null
  return {
    uid: user.uid || null,
    role: user.role || 'staff',
    companyId: getCurrentCompanyId() || null,
    displayName: user.displayName || '',
    email: user.email || '',
    companyName: user.companyName || ''
  }
}

/**
 * Check if user has admin or manager role
 */
export const isAdminOrManager = (): boolean => {
  const userInfo = getCurrentUserInfo()
  if (!userInfo) return false
  return (
    userInfo.role === 'admin' ||
    userInfo.role === 'org_admin' ||
    userInfo.role === 'super_admin' ||
    userInfo.role === 'manager'
  )
}

/**
 * Check if user has specific role
 */
export const hasRole = (role: string): boolean => {
  const userInfo = getCurrentUserInfo()
  if (!userInfo) return false
  return userInfo.role === role
}
